// ============================================================
// 횠짠횢혙횠짰횠쨌횢혞횠짤 1: 횢혗횠짠횠짝횢혚횠짤 횠짠횢혙횠쨔횢혚횢혙횠짠횠짧 횠짠횢혙횢혚횠짹횠짠횠짱 횠짭횢혙횠짢 횠짢횢혡횠짠횢혛횠짠횠짧횢혝횠짠 횠짠횢혙횠짧횠짠횠짹횢혡횠짰횢혡횠짤
// 횠짙횠쨋횢혖 횠짙횢혞 횠짠횠짯횠째횢혖 횠쨔횢혚횢혙횠짠횠짧 횠짯횠쨀횠짢 횠짠횠짯횠짧횢혡횠짠횠짭횢혘
// ============================================================
const coins = [
  "BTCUSDT",
  "ETHUSDT",
  "BNBUSDT",
  "SOLUSDT",
  "XRPUSDT",
  "ADAUSDT",
  "DOGEUSDT",
  "AVAXUSDT",
  "LINKUSDT",
  "LTCUSDT"
];

return coins.map(coin => ({ json: { symbol: coin } }));

// ============================================================
// 횠짠횢혙횠짰횠쨌횢혞횠짤 3: 횠짧횢혛횠쨀횢혡횢혗 횠짢횢혡횠짠횢혛횠짠횠짧 횠짠횢혙횠쨈횢혚횢혞횠쨔 (Klines) 횢혙횢혘횢혙 횠쨔횢혚횢혙횠짤
// ============================================================

// 횠짭횢혙횠짢 횠짠횠쨀횢혚 횠짠횢혙횠쨔횢혚횢혙횠짤 횢혚횢혛 횢혛횢혞횠짱 횠짠횢혙횢혙횢혞횠짢
const symbol = $('Loop Over Items').item.json.symbol;

// 횠짠횢혙횠짧횠짯횢혗횢혗 횢혚횢혛 횢혞횠짭횢혞횠짱 횠짢횢혡횠짠횢혛횠짠횠짧
if (!items || items.length === 0) {
  console.log(`No data received for ${symbol}`);
  return [];
}

const formattedData = [];

for (const item of items) {
  const candle = item.json;

  // 횠짠횢혙횠짧횠짯횢혗횢혗 횢혚횢혛 횠쨉횠짯횠짤 횠짠횢혙횠쨉횢혖
  if (!Array.isArray(candle) || candle.length < 6) {
    continue;
  }

  const openPrice  = parseFloat(candle[1]);
  const highPrice  = parseFloat(candle[2]);
  const lowPrice   = parseFloat(candle[3]);
  const closePrice = parseFloat(candle[4]);
  const volume     = parseFloat(candle[5]);

  // 횠짧횠짭횢혛횠짢 횠짠횢혙횢혗횠쨀횢혚횠짤 횠쨔횢혙횢혟 횠쨉횢혖횠짹
  const change24h = openPrice !== 0
    ? ((closePrice - openPrice) / openPrice) * 100
    : 0;

  formattedData.push({
    json: {
      symbol:     symbol,
      time:       new Date(candle[0]).toISOString(),
      open:       openPrice,
      high:       highPrice,
      low:        lowPrice,
      price:      closePrice,
      volume:     volume,
      change_24h: parseFloat(change24h.toFixed(4))
    }
  });
}

console.log(`Formatted ${formattedData.length} candles for ${symbol}`);
return formattedData;
